// Configure physics toast
if (typeof toast !== 'undefined') {
    toast.defaults = {
        position: 'top-right',
        duration: 4000,
        showProgress: true,
        pauseOnHover: true,
        spring: true
    };
}

// Helper functions
function getAuthToken() {
    return localStorage.getItem('token') || sessionStorage.getItem('token');
}

function handleLogout() {
    localStorage.removeItem('token');
    localStorage.removeItem('role');
    sessionStorage.removeItem('token');
    sessionStorage.removeItem('role');
    toast.success('Logged out', 'You have been successfully logged out.');
    setTimeout(() => {
        window.location.href = '/login.html';
    }, 1500);
}

// Check authentication
function checkAuth() {
    const token = getAuthToken();
    if (!token) {
        toast.warning('Authentication required', 'Please log in to view your reports.');
        setTimeout(() => {
            window.location.href = '/login.html';
        }, 2000);
        return false;
    }
    return true;
}

// Get status class
function getStatusClass(status) {
    const statusMap = {
        'pending': 'status-pending',
        'investigating': 'status-investigating',
        'resolved': 'status-resolved'
    };
    return statusMap[status?.toLowerCase()] || 'status-pending';
}

function getStatusText(status) {
    const statusMap = {
        'pending': 'Pending',
        'investigating': 'Investigating',
        'resolved': 'Resolved'
    };
    return statusMap[status?.toLowerCase()] || 'Pending';
}

let reportsData = [];
let currentPage = 1;
let totalPages = 1;
let totalItems = 0;
const rowsPerPage = 5;

// Fetch reports from API
async function fetchReports(page = 1) {
    const token = getAuthToken();
    if (!token) return;

    const loadingState = document.getElementById('loadingState');
    const desktopView = document.getElementById('desktopView');
    const noReportsState = document.getElementById('noReportsState');

    loadingState.classList.remove('hidden');
    desktopView.classList.add('hidden');
    noReportsState.classList.add('hidden');

    try {
        const response = await fetch(`https://safespace-back.onrender.com/api/v1/user/reports?page=${page}&limit=${rowsPerPage}`, {
            method: 'GET',
            headers: {
                'Authorization': `Bearer ${token}`,
                'Accept': 'application/json'
            }
        });

        const data = await response.json();

        if (response.ok && data.success) {
            reportsData = data.data || [];
            totalItems = data.pagination?.total || 0;
            totalPages = data.pagination?.totalPages || 1;
            currentPage = data.pagination?.page || page;

            document.getElementById('total-count').innerText = totalItems + ' total';

            if (reportsData.length === 0) {
                desktopView.classList.add('hidden');
                noReportsState.classList.remove('hidden');
            } else {
                desktopView.classList.remove('hidden');
                noReportsState.classList.add('hidden');
                renderDesktop();
            }
        } else {
            toast.error('Error', data.message || 'Failed to fetch reports');
        }
    } catch (error) {
        console.error('Error fetching reports:', error);
        toast.error('Connection error', 'Unable to connect to server.');
    } finally {
        loadingState.classList.add('hidden');
    }
}

function getFullName(report) {
    const firstName = report.firstName || '';
    const middleName = report.middleName || '';
    const lastName = report.lastName || '';
    return `${firstName} ${middleName} ${lastName}`.trim();
}

function formatDate(dateString) {
    if (!dateString) return 'N/A';
    try {
        const date = new Date(dateString);
        return date.toLocaleDateString('en-US', {
            year: 'numeric',
            month: 'long',
            day: 'numeric',
            hour: '2-digit',
            minute: '2-digit'
        });
    } catch (e) {
        return dateString;
    }
}

function renderDesktop() {
    const start = (currentPage - 1) * rowsPerPage;
    const end = Math.min(start + rowsPerPage, totalItems);
    
    const tbody = document.getElementById('desktop-table-body');
    tbody.innerHTML = reportsData.map(r => `
        <tr class="border-b border-[#F0E4E4] hover:bg-[#FDF8F8]">
            <td class="p-3 text-sm">${getFullName(r)}</td>
            <td class="p-3 text-sm">${r.mobileNumber || 'N/A'}</td>
            <td class="p-3 text-sm">${r.classification || 'N/A'}</td>
            <td class="p-3 text-sm">${r.complainedFullName || 'N/A'}</td>
            <td class="p-3 text-sm">${r.procedureType || 'N/A'}</td>
            <td class="p-3"><span class="status-badge ${getStatusClass(r.status)}">${getStatusText(r.status)}</span></td>
            <td class="p-3"><button onclick="viewReportDetails(${JSON.stringify(r).replace(/"/g, '&quot;')})" class="text-up text-sm hover:underline">View</button></td>
        </tr>
    `).join('');

    // Desktop pagination
    document.getElementById('desktop-pagination').innerHTML = `
        <div class="text-xs text-[#8F7E7E]">Showing ${start+1}–${end} of ${totalItems}</div>
        <div class="flex gap-2">${getPaginationButtons()}</div>
    `;
}

function getPaginationButtons() {
    let buttons = '';
    
    buttons += `<button class="pagination-btn" ${currentPage === 1 ? 'disabled' : ''} onclick="changePage(${currentPage-1})"><i class="fas fa-chevron-left text-xs"></i></button>`;
    
    for (let i = 1; i <= totalPages; i++) {
        if (i === 1 || i === totalPages || (i >= currentPage-1 && i <= currentPage+1)) {
            buttons += `<button class="pagination-btn ${i === currentPage ? 'active' : ''}" onclick="changePage(${i})">${i}</button>`;
        } else if (i === currentPage-2 || i === currentPage+2) {
            buttons += `<span class="px-2 text-[#8F7E7E]">...</span>`;
        }
    }
    
    buttons += `<button class="pagination-btn" ${currentPage === totalPages ? 'disabled' : ''} onclick="changePage(${currentPage+1})"><i class="fas fa-chevron-right text-xs"></i></button>`;
    
    return buttons;
}

window.changePage = function(newPage) {
    if (newPage < 1 || newPage > totalPages) return;
    fetchReports(newPage);
};

