window.downloadPDF = function () {
    // Get the current report data from the modal - updated selectors
    const modalContent = document.getElementById('modalContent');
    
    // Extract data from the new layout
    const reportData = {};
    
    // Get data from label-value pairs (flex items)
    const fieldRows = modalContent.querySelectorAll('.flex');
    fieldRows.forEach(row => {
        const label = row.querySelector('.text-gray-500')?.innerText;
        const value = row.querySelector('.text-gray-800')?.innerText;
        if (label && value) {
            reportData[label] = value !== 'N/A' ? value : '';
        }
    });
    
    // Get long text fields
    const incidentDetails = modalContent.querySelector('.bg-gray-50.rounded-lg.p-3.text-sm')?.innerText;
    if (incidentDetails) reportData['Incident Details'] = incidentDetails;
    
    const incidentEvent = modalContent.querySelectorAll('.bg-gray-50.rounded-lg.p-3.text-sm')[1]?.innerText;
    if (incidentEvent) reportData['Incident Event'] = incidentEvent;
    
    const physicalAppearance = modalContent.querySelectorAll('.bg-gray-50.rounded-lg.p-3.text-sm')[2]?.innerText;
    if (physicalAppearance) reportData['Physical Appearance'] = physicalAppearance;
    
    // Get status and ID from the top bar
    const reportId = modalContent.querySelector('.text-gray-500.font-mono')?.innerText?.replace('ID: ', '');
    if (reportId) reportData['Report ID'] = reportId;
    
    const status = modalContent.querySelector('.rounded-full.text-xs')?.innerText;
    if (status) reportData['Status'] = status;
    
    // Get date from the fields (it's already in the data)
    // Date Reported and Last Updated are already in the fields

    // Create a hidden iframe to load the PDF form
    const iframe = document.createElement('iframe');
    iframe.style.position = 'absolute';
    iframe.style.width = '0';
    iframe.style.height = '0';
    iframe.style.border = 'none';
    document.body.appendChild(iframe);

    const formHtml = getFormHTML();
    
    iframe.contentWindow.document.open();
    iframe.contentWindow.document.write(formHtml);
    iframe.contentWindow.document.close();

    iframe.onload = function() {
        const doc = iframe.contentWindow.document;
        
        // Fill in all fields with report data
        const now = new Date();
        if (doc.querySelector('input[name="date"]')) {
            doc.querySelector('input[name="date"]').value = reportData['Date Reported'] || now.toLocaleDateString();
        }
        if (doc.querySelector('input[name="time"]')) {
            doc.querySelector('input[name="time"]').value = now.toLocaleTimeString();
        }
        
        if (doc.querySelector('input[name="fullName"]')) {
            doc.querySelector('input[name="fullName"]').value = reportData['Full Name'] || '';
        }
        if (doc.querySelector('input[name="age"]')) {
            doc.querySelector('input[name="age"]').value = reportData['Age'] || '';
        }
        
        const bioSex = reportData['Biological Sex']?.toLowerCase();
        if (bioSex === 'male' && doc.querySelector('input[name="bioGender"][value="male"]')) {
            doc.querySelector('input[name="bioGender"][value="male"]').checked = true;
        } else if (bioSex === 'female' && doc.querySelector('input[name="bioGender"][value="female"]')) {
            doc.querySelector('input[name="bioGender"][value="female"]').checked = true;
        }
        
        const identifiedAs = reportData['Identified As']?.toLowerCase();
        if (identifiedAs === 'male' && doc.querySelector('input[name="idGender"][value="male"]')) {
            doc.querySelector('input[name="idGender"][value="male"]').checked = true;
        } else if (identifiedAs === 'female' && doc.querySelector('input[name="idGender"][value="female"]')) {
            doc.querySelector('input[name="idGender"][value="female"]').checked = true;
        }
        
        if (doc.querySelector('input[name="civilStatus"]')) {
            doc.querySelector('input[name="civilStatus"]').value = reportData['Civil Status'] || '';
        }
        
        if (doc.querySelector('textarea[name="presentAddress"]')) {
            doc.querySelector('textarea[name="presentAddress"]').value = reportData['Present Address'] || '';
        }
        if (doc.querySelector('textarea[name="permanentAddress"]')) {
            doc.querySelector('textarea[name="permanentAddress"]').value = reportData['Permanent Address'] || '';
        }
        
        if (doc.querySelector('input[name="mobile"]')) {
            doc.querySelector('input[name="mobile"]').value = reportData['Mobile Number'] || '';
        }
        if (doc.querySelector('input[name="landline"]')) {
            doc.querySelector('input[name="landline"]').value = reportData['Landline Number'] || '';
        }
        
        const classification = reportData['Classification']?.toLowerCase();
        if (classification && doc.querySelector(`input[name="classification"][value="${classification}"]`)) {
            doc.querySelector(`input[name="classification"][value="${classification}"]`).checked = true;
        }
        
        if (doc.querySelector('input[name="college"]')) {
            doc.querySelector('input[name="college"]').value = reportData['College'] || '';
        }
        if (doc.querySelector('input[name="department"]')) {
            doc.querySelector('input[name="department"]').value = reportData['Department/Unit'] || '';
        }
        
        if (doc.querySelector('input[name="respondentName"]')) {
            doc.querySelector('input[name="respondentName"]').value = reportData['Respondent Full Name'] || '';
        }
        
        const respSex = reportData['Respondent Sex']?.toLowerCase();
        if (respSex === 'male' && doc.querySelector('input[name="respGender"][value="male"]')) {
            doc.querySelector('input[name="respGender"][value="male"]').checked = true;
        } else if (respSex === 'female' && doc.querySelector('input[name="respGender"][value="female"]')) {
            doc.querySelector('input[name="respGender"][value="female"]').checked = true;
        }
        
        const respClass = reportData['Respondent Classification']?.toLowerCase();
        if (respClass && doc.querySelector(`input[name="respClassification"][value="${respClass}"]`)) {
            doc.querySelector(`input[name="respClassification"][value="${respClass}"]`).checked = true;
        }
        
        if (doc.querySelector('input[name="respCollege"]')) {
            doc.querySelector('input[name="respCollege"]').value = reportData['Respondent College'] || '';
        }
        if (doc.querySelector('input[name="respDepartment"]')) {
            doc.querySelector('input[name="respDepartment"]').value = reportData['Respondent Department'] || '';
        }
        if (doc.querySelector('input[name="respVictimConstituent"]')) {
            doc.querySelector('input[name="respVictimConstituent"]').value = reportData['Is the Victim a UP Constituent?'] || '';
        }
        if (doc.querySelector('input[name="respComplainedConstituent"]')) {
            doc.querySelector('input[name="respComplainedConstituent"]').value = reportData['Is the Perpetiator a UP Constituent?'] || '';
        }
        if (doc.querySelector('input[name="respComplainedInsideCampus"]')) {
            doc.querySelector('input[name="respComplainedInsideCampus"]').value = reportData['Did the incident happen inside campus premises?'] || '';
        }
        
        if (doc.querySelector('textarea[name="story"]')) {
            let story = reportData['Incident Details'] || '';
            if (reportData['Incident Event']) story += '\n\nIncident Event: ' + reportData['Incident Event'];
            if (reportData['Physical Appearance']) story += '\n\nPhysical Appearance: ' + reportData['Physical Appearance'];
            doc.querySelector('textarea[name="story"]').value = story;
        }
        
        const procedure = reportData['Procedure Type']?.toLowerCase();
        if (procedure) {
            if (doc.querySelector('input[name="proceed"][value="yes"]')) {
                doc.querySelector('input[name="proceed"][value="yes"]').checked = true;
                const procedureSection = doc.getElementById('procedureSection');
                if (procedureSection) procedureSection.classList.add('show');
            }
            if (procedure.includes('formal') && doc.querySelector('input[name="procedure"][value="formal"]')) {
                doc.querySelector('input[name="procedure"][value="formal"]').checked = true;
            } else if (procedure.includes('informal') && doc.querySelector('input[name="procedure"][value="informal"]')) {
                doc.querySelector('input[name="procedure"][value="informal"]').checked = true;
            }
        }
        
        const heardFrom = reportData['Where did you hear about us?']?.toLowerCase();
        if (heardFrom) {
            const heardMap = {
                'orientations': 'orientations',
                'flyers': 'flyers',
                'word': 'wordofmouth',
                'social': 'socialmedia',
                'caravan': 'caravan'
            };
            for (const [key, value] of Object.entries(heardMap)) {
                if (heardFrom.includes(key) && doc.querySelector(`input[name="heard"][value="${value}"]`)) {
                    doc.querySelector(`input[name="heard"][value="${value}"]`).checked = true;
                }
            }
            if (heardFrom.includes('other') && doc.querySelector('input[name="heard"][value="others"]')) {
                doc.querySelector('input[name="heard"][value="others"]').checked = true;
            }
        }
        
        if (doc.querySelector('input[name="recordedBy"]')) {
            const fullName = reportData['Full Name'] || '';
            doc.querySelector('input[name="recordedBy"]').value = fullName;
        }
        if (doc.querySelector('input[name="recordedDate"]')) {
            doc.querySelector('input[name="recordedDate"]').value = reportData['Date Reported'] || new Date().toLocaleDateString();
        }
        
        // Trigger print/PDF download
        setTimeout(() => {
            iframe.contentWindow.print();
            setTimeout(() => {
                document.body.removeChild(iframe);
            }, 1000);
        }, 500);
    };
};

